noncompliant:
void my_log(const char* format, ...);

void f() {
  std::string someStr = "foo";
  my_log("%s", someStr);  // Noncompliant; the C++11 standard requires types passed as variadic arguments to have a trivial copy constructor

  std::string_view someStrView = "bar";
  my_log("%s", someStrView); // Noncompliant; user-defined type passed as variadic argument
  std::chrono::duration<float> duration;
  my_log("%f", duration); // Noncompliant; user-defined type passed as variadic argument
}

compliant:
void my_log(const char* format, ...);

void f() {
  std::string someStr = "foo";
  my_log("%s", someStr.c_str());  // Compliant: pass the underlying C string

  std::string_view someStrView = "bar";
  my_log("%s", someStrView.data()); // Compliant: pass the underlying data
  std::chrono::duration<float> duration;
  my_log("%f", duration.count()); // Compliant: pass the underlying count
}
